+  slotProps={{
+    legend: {
+      axisDirection: 'y',
+      direction: '${props.direction}',
+      thickness: ${props.thickness},
+      labelPosition: '${props.labelPosition}',
+      reverse: ${props.reverse},
+      sx: { ${props.direction === 'horizontal' ? 'width' : 'height'}: '${props.length}${props.direction === 'horizontal' ? '%' : 'px'}' },
+    },
+  }}
+/>
+`;
+      }}
+    />
+  );
+}

