+<PieChart
+  {/** ... */}
+  slotProps={{
+    legend: {
+      direction: props.direction,
+      sx: {
+        gap: '${props.itemGap}px',
+        // CSS-in-JS
+        [\`.\${legendClasses.mark}\`]: {
+          height: ${props.markSize},
+          width: ${props.markSize},
+        },
+        // CSS class
+        ['.${legendClasses.series}']: {
+          gap: '${props.markGap}px',
+        },
+      },
+    },
+  }}
+/>
+`;
+      }}
+    />
+  );
